import{_ as t,c as o,o as r,ae as a}from"./chunks/framework.OrwUijoT.js";const p=JSON.parse('{"title":"Server Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"en/architecture.md"}'),i={name:"architecture.md"};function d(s,e,n,c,l,u){return r(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="server-architecture" tabindex="-1">Server Architecture <a class="header-anchor" href="#server-architecture" aria-label="Permalink to &quot;Server Architecture&quot;">​</a></h1><p>clice uses a <strong>multi-process architecture</strong> where a single <strong>Master Server</strong> coordinates multiple <strong>Worker</strong> processes. This design isolates Clang AST operations (which are memory-heavy and may crash) from the main LSP event loop.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐   JSON/LSP    ┌────────────────┐   Bincode/IPC   ┌──────────────────┐</span></span>
<span class="line"><span>│   LSP Client │ ◄──────────► │  Master Server  │ ◄─────────────► │ Stateful Workers │</span></span>
<span class="line"><span>│   (Editor)   │    (stdio)    │                 │    (stdio)      │  (AST cache)     │</span></span>
<span class="line"><span>└──────────────┘               │  - Lifecycle    │                 └──────────────────┘</span></span>
<span class="line"><span>                               │  - Documents    │</span></span>
<span class="line"><span>                               │  - CDB          │   Bincode/IPC   ┌──────────────────┐</span></span>
<span class="line"><span>                               │  - Build drain  │ ◄─────────────► │ Stateless Workers│</span></span>
<span class="line"><span>                               │  - Indexing     │    (stdio)      │  (one-shot tasks)│</span></span>
<span class="line"><span>                               └────────────────┘                 └──────────────────┘</span></span></code></pre></div><h2 id="master-server" tabindex="-1">Master Server <a class="header-anchor" href="#master-server" aria-label="Permalink to &quot;Master Server&quot;">​</a></h2><p>The master server (<code>src/server/master_server.cpp</code>) is the central coordinator. It runs a single-threaded async event loop and never touches Clang directly. Its responsibilities:</p><h3 id="lsp-lifecycle" tabindex="-1">LSP Lifecycle <a class="header-anchor" href="#lsp-lifecycle" aria-label="Permalink to &quot;LSP Lifecycle&quot;">​</a></h3><p>The server progresses through these states:</p><ol><li><strong>Uninitialized</strong> — waiting for <code>initialize</code> request</li><li><strong>Initialized</strong> — capabilities exchanged, waiting for <code>initialized</code> notification</li><li><strong>Ready</strong> — workers spawned, workspace loaded, accepting requests</li><li><strong>ShuttingDown</strong> — <code>shutdown</code> received, draining work</li><li><strong>Exited</strong> — <code>exit</code> received, stopping the event loop</li></ol><p>On <code>initialized</code>, the master:</p><ul><li>Loads configuration from <code>clice.toml</code> (or uses defaults)</li><li>Starts the worker pool (spawns stateful + stateless processes)</li><li>Loads <code>compile_commands.json</code> and builds an include graph</li><li>Starts the background indexer coroutine (if enabled)</li></ul><h3 id="document-management" tabindex="-1">Document Management <a class="header-anchor" href="#document-management" aria-label="Permalink to &quot;Document Management&quot;">​</a></h3><p>Each open document is tracked in a <code>DocumentState</code> with:</p><ul><li>Current <code>version</code> and <code>text</code> (kept in sync via <code>didOpen</code>/<code>didChange</code>)</li><li>A <code>generation</code> counter to detect stale compile results</li><li>Build state flags (<code>build_running</code>, <code>build_requested</code>, <code>drain_scheduled</code>)</li></ul><p>When a document is opened or changed:</p><ol><li>The include graph is re-scanned (via dependency directives)</li><li>The compile unit is registered/updated in the <code>CompileGraph</code></li><li>A debounced build is scheduled</li></ol><h3 id="build-drain" tabindex="-1">Build Drain <a class="header-anchor" href="#build-drain" aria-label="Permalink to &quot;Build Drain&quot;">​</a></h3><p>The <code>run_build_drain</code> coroutine implements debounced compilation:</p><ol><li>Wait for the debounce timer (default 200ms) to expire</li><li>Ensure PCH/PCM dependencies are ready via <code>CompileGraph</code></li><li>Send a <code>compile</code> request to the assigned stateful worker</li><li>Publish diagnostics from the result (or clear them on failure)</li><li>If more edits arrived during compilation (<code>build_requested</code>), loop back to step 2</li></ol><p>This ensures rapid typing doesn&#39;t trigger a compile per keystroke.</p><h3 id="request-routing" tabindex="-1">Request Routing <a class="header-anchor" href="#request-routing" aria-label="Permalink to &quot;Request Routing&quot;">​</a></h3><p>Feature requests are split between two worker types:</p><p><strong>Stateful workers</strong> (affinity-routed by file path):</p><ul><li><code>textDocument/hover</code></li><li><code>textDocument/semanticTokens/full</code></li><li><code>textDocument/inlayHint</code></li><li><code>textDocument/foldingRange</code></li><li><code>textDocument/documentSymbol</code></li><li><code>textDocument/documentLink</code></li><li><code>textDocument/codeAction</code></li><li><code>textDocument/definition</code></li></ul><p><strong>Stateless workers</strong> (round-robin):</p><ul><li><code>textDocument/completion</code></li><li><code>textDocument/signatureHelp</code></li></ul><p>All feature responses use <code>RawValue</code> passthrough — the worker serializes the LSP result to JSON, and the master forwards the raw JSON bytes to the client without deserializing. This avoids bincode↔JSON conversion overhead and serde annotation conflicts.</p><h2 id="worker-pool" tabindex="-1">Worker Pool <a class="header-anchor" href="#worker-pool" aria-label="Permalink to &quot;Worker Pool&quot;">​</a></h2><p>The worker pool (<code>src/server/worker_pool.cpp</code>) manages spawning and communicating with worker processes. Each worker is a child process of the same <code>clice</code> binary, launched with <code>--mode stateful-worker</code> or <code>--mode stateless-worker</code>.</p><h3 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to &quot;Communication&quot;">​</a></h3><p>Workers communicate with the master via <strong>stdio pipes</strong> using a <strong>bincode</strong> serialization format (via <code>kota::ipc::BincodePeer</code>). This is more compact and faster than JSON for internal IPC, while the master handles JSON for the external LSP protocol.</p><h3 id="stateful-worker-routing" tabindex="-1">Stateful Worker Routing <a class="header-anchor" href="#stateful-worker-routing" aria-label="Permalink to &quot;Stateful Worker Routing&quot;">​</a></h3><p>Stateful workers use <strong>affinity routing</strong>: each file is consistently assigned to the same worker so that the worker retains the cached AST. Assignment uses a <strong>least-loaded</strong> strategy for new files, with <strong>LRU tracking</strong> to manage ownership.</p><p>When a worker exceeds its document capacity (currently hardcoded at 16 documents), it evicts the least-recently-used document and notifies the master via an <code>evicted</code> notification.</p><h3 id="stateless-worker-routing" tabindex="-1">Stateless Worker Routing <a class="header-anchor" href="#stateless-worker-routing" aria-label="Permalink to &quot;Stateless Worker Routing&quot;">​</a></h3><p>Stateless workers use simple <strong>round-robin</strong> dispatch. Each request includes the full source text and compilation arguments, so any worker can handle it independently.</p><h2 id="stateful-worker" tabindex="-1">Stateful Worker <a class="header-anchor" href="#stateful-worker" aria-label="Permalink to &quot;Stateful Worker&quot;">​</a></h2><p>The stateful worker (<code>src/server/stateful_worker.cpp</code>) caches compiled ASTs in memory. Key behavior:</p><ul><li><strong>Compile</strong>: Parses source code into a <code>CompilationUnit</code>, caches the AST, and returns diagnostics as a <code>RawValue</code> (JSON bytes)</li><li><strong>Feature queries</strong>: Look up the cached AST and invoke the corresponding <code>feature::*</code> function (hover, semantic tokens, etc.), serializing the result to JSON</li><li><strong>Document updates</strong>: Received as notifications — the worker updates the stored text and marks the document as <code>dirty</code>, causing feature queries to return <code>null</code> until recompilation</li><li><strong>Eviction</strong>: LRU-based; evicts the oldest document when capacity is exceeded, notifying the master</li><li><strong>Concurrency</strong>: Each document has a per-document <code>kota::mutex</code> (strand) to serialize compilation and feature queries. Heavy work (compilation, feature extraction) runs on a thread pool via <code>kota::queue</code>.</li></ul><h2 id="stateless-worker" tabindex="-1">Stateless Worker <a class="header-anchor" href="#stateless-worker" aria-label="Permalink to &quot;Stateless Worker&quot;">​</a></h2><p>The stateless worker (<code>src/server/stateless_worker.cpp</code>) handles one-shot requests that don&#39;t benefit from cached ASTs:</p><ul><li><strong>Completion</strong>: Creates a fresh compilation with <code>CompilationKind::Completion</code> and invokes <code>feature::code_complete</code></li><li><strong>Signature help</strong>: Similar to completion, using <code>feature::signature_help</code></li><li><strong>Build PCH</strong>: Compiles a precompiled header to a temporary file</li><li><strong>Build PCM</strong>: Compiles a C++20 module interface to a temporary file</li><li><strong>Index</strong>: Compiles a file for indexing (TUIndex generation — currently a stub)</li></ul><p>All requests are dispatched to a thread pool via <code>kota::queue</code>.</p><h2 id="compile-graph" tabindex="-1">Compile Graph <a class="header-anchor" href="#compile-graph" aria-label="Permalink to &quot;Compile Graph&quot;">​</a></h2><p>The compile graph (<code>src/server/compile_graph.cpp</code>) tracks compilation unit dependencies as a DAG. It handles:</p><ul><li><strong>Registration</strong>: Each file registers its included dependencies</li><li><strong>Cascade invalidation</strong>: When a file changes, all transitive dependents are marked dirty and their ongoing compilations are cancelled</li><li><strong>Dependency compilation</strong>: Before compiling a file, <code>compile_deps</code> ensures all dependencies (PCH, PCMs) are built first</li><li><strong>Cancellation</strong>: Uses <code>kota::cancellation_source</code> to abort in-flight compilations when files are invalidated</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The server reads configuration from <code>clice.toml</code> (or <code>.clice/config.toml</code>) in the workspace root. If no config file exists, sensible defaults are computed from system resources:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>stateful_worker_count</code></td><td>CPU cores / 4</td><td>Number of stateful worker processes</td></tr><tr><td><code>stateless_worker_count</code></td><td>CPU cores / 4</td><td>Number of stateless worker processes</td></tr><tr><td><code>worker_memory_limit</code></td><td>4 GB</td><td>Memory limit per stateful worker</td></tr><tr><td><code>compile_commands_path</code></td><td>auto-detect</td><td>Path to <code>compile_commands.json</code></td></tr><tr><td><code>cache_dir</code></td><td><code>&lt;workspace&gt;/.clice/</code></td><td>Cache directory for PCH/PCM files</td></tr><tr><td><code>debounce_ms</code></td><td>200</td><td>Debounce interval for recompilation</td></tr><tr><td><code>enable_indexing</code></td><td>true</td><td>Enable background indexing</td></tr><tr><td><code>idle_timeout_ms</code></td><td>3000</td><td>Idle time before background indexing starts</td></tr></tbody></table><p>String values support <code>\${workspace}</code> substitution.</p><h2 id="ipc-protocol" tabindex="-1">IPC Protocol <a class="header-anchor" href="#ipc-protocol" aria-label="Permalink to &quot;IPC Protocol&quot;">​</a></h2><p>The master and workers communicate using custom RPC messages defined in <code>src/server/protocol.h</code>. Each message type has a <code>RequestTraits</code> or <code>NotificationTraits</code> specialization that defines the method name and result type.</p><h3 id="stateful-worker-messages" tabindex="-1">Stateful Worker Messages <a class="header-anchor" href="#stateful-worker-messages" aria-label="Permalink to &quot;Stateful Worker Messages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Direction</th><th>Purpose</th></tr></thead><tbody><tr><td><code>clice/worker/compile</code></td><td>Request</td><td>Compile source and return diagnostics</td></tr><tr><td><code>clice/worker/hover</code></td><td>Request</td><td>Get hover info at position</td></tr><tr><td><code>clice/worker/semanticTokens</code></td><td>Request</td><td>Get semantic tokens for file</td></tr><tr><td><code>clice/worker/inlayHints</code></td><td>Request</td><td>Get inlay hints for range</td></tr><tr><td><code>clice/worker/foldingRange</code></td><td>Request</td><td>Get folding ranges</td></tr><tr><td><code>clice/worker/documentSymbol</code></td><td>Request</td><td>Get document symbols</td></tr><tr><td><code>clice/worker/documentLink</code></td><td>Request</td><td>Get document links</td></tr><tr><td><code>clice/worker/codeAction</code></td><td>Request</td><td>Get code actions for range</td></tr><tr><td><code>clice/worker/goToDefinition</code></td><td>Request</td><td>Go to definition at position</td></tr><tr><td><code>clice/worker/documentUpdate</code></td><td>Notification</td><td>Update document text (marks dirty)</td></tr><tr><td><code>clice/worker/evict</code></td><td>Notification</td><td>Master → Worker: evict a document</td></tr><tr><td><code>clice/worker/evicted</code></td><td>Notification</td><td>Worker → Master: document was evicted</td></tr></tbody></table><h3 id="stateless-worker-messages" tabindex="-1">Stateless Worker Messages <a class="header-anchor" href="#stateless-worker-messages" aria-label="Permalink to &quot;Stateless Worker Messages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Direction</th><th>Purpose</th></tr></thead><tbody><tr><td><code>clice/worker/completion</code></td><td>Request</td><td>Code completion at position</td></tr><tr><td><code>clice/worker/signatureHelp</code></td><td>Request</td><td>Signature help at position</td></tr><tr><td><code>clice/worker/buildPCH</code></td><td>Request</td><td>Build precompiled header</td></tr><tr><td><code>clice/worker/buildPCM</code></td><td>Request</td><td>Build C++20 module interface</td></tr><tr><td><code>clice/worker/index</code></td><td>Request</td><td>Index a translation unit</td></tr></tbody></table>`,56)])])}const m=t(i,[["render",d]]);export{p as __pageData,m as default};
